from typing import List, FrozenSet, Set, Tuple, Dict, Anyfrom ._a_base_covpyebyeaggr import _ABaseCoverageEbyeAggregator# ============ Path Utilities ============ #from os.path import (	join as path_join,	sep as path_sep,	altsep as path_altsep,	splitext as path_split_ext)_PATH_SEPS: str = f"{path_sep}{path_altsep if path_altsep is not None else ''}"# ======================================== ## ============== JSON Utilities ============== #from json import (	JSONDecoder, JSONDecodeError)# ============================================ #from tree_sitter import (	Language, Parser,	Node as TreeNode)from tree_sitter_python import language as py_grammarfrom ..exceptions import WrongReportTypeErrorclass JsonCoverageEbyeAggregator(_ABaseCoverageEbyeAggregator):	"""		Rappresenta un `ICoverageFbyfAggregator` che è capace di trattare i report		di coverage.py di tipologia JSON	"""		_ENTS_TYPES: FrozenSet[str] = { "function_definition", "async_function_definition" }		_CONSTANT_TYPES: FrozenSet[str] = {		"string", "integer", "float", "true", "false", "none", "ellipsis",		"tuple", "list", "set", "frozenset", "dictionary", "literal", "object"	}		def __init__(self):		"""			Costruisce un nuovo JsonCoverageEbyeAggregator		"""		super().__init__()				self._json_dec: JSONDecoder = JSONDecoder()		self._py_parser: Parser = Parser(Language(py_grammar()))		self._module_source: bytes = None		self._module: TreeNode = None					def _ap__assert_report_type(self, report_path: str):		if not report_path.lower().endswith('.json'):			raise WrongReportTypeError()				with open(report_path, "r") as fpreport:			try:				self._json_dec.decode(fpreport.read())			except JSONDecodeError:				raise WrongReportTypeError()							def _ap__aggregate_spec(			self,			report_path: str,			focal_root: str,			aggr_path: str,			exclusions: Set[str],	):		entities_covdata: Dict[str, Tuple[float, int, int]] = dict()		parsed_covdata: Dict[str, Set[int]] = self._parse_covpy_report(report_path)				module_path: str		source_lines: List[str]		executable_lines: Set[int]		module_entities: Dict[str, Tuple[int, int]]				total_lines: int		covered_lines: int		entity_coverage: float				entity_start: int		entity_end: int				for dotted_module_path, executed_lines in parsed_covdata.items():			module_path = path_join(focal_root, *dotted_module_path.split("."))						with open(module_path, "r") as fpmodule:				self._module_source = fpmodule.read().encode("utf-8")			self._module = self._py_parser.parse(self._module_source).root_node						module_entities = self._extract_module_entities(dotted_module_path)			executable_lines = self._extract_execlines()						total_lines = 0			covered_lines = 0			for entity_name in module_entities.keys():				if entity_name in exclusions:					continue				entity_start = module_entities[entity_name][0]				entity_end = module_entities[entity_name][1]								for lineno in range(entity_start, entity_end+1):					if lineno not in executable_lines:						continue					total_lines += 1					if lineno in executed_lines:						covered_lines += 1										entity_coverage = (covered_lines / total_lines) if total_lines > 0 else 1.0				entities_covdata[entity_name] = (				    round(entity_coverage, 6),					covered_lines,					total_lines				)						return entities_covdata			##	============================================================	##						PRIVATE METHODS	##	============================================================			def _parse_covpy_report(self, covpy_report_path: str) -> Dict[str, Set[int]]:		"""			Effettua il parsing del report JSON di coverage.py restituendo,			per ogni modulo identificato dalla sua "dotted path" le linee coperte			dai test cases a cui è legato il report.						Parameters			----------				covpy_report_path: str					Una stringa contenente la path al report JSON di coverage.py					di cui effettuare il parsing								Returns			-------				Dict[str, Set[int]]					Un dizionario di insiemi di interi, indicizzato da stringhe, contenente, per ogni					modulo focale parte del report, l' insieme delle linee di codice esercitate dai tests		"""		report_json: Dict[str, Dict[str, Any]]		with open(covpy_report_path, "r") as fpreport:			report_json = self._json_dec.decode(fpreport.read()).get("files", dict())					parsed_covdata: Dict[str, Set[int]] = dict()		path_parts: List[str]		last_elem: int		executed_lines: Set[int] = set()				module_name: str		dotted_module_path: str		for file_path, cov_info in report_json.items():			path_parts = file_path.split("/")						last_elem = len(path_parts)-1			path_parts[last_elem] = path_split_ext(path_parts[last_elem])[0]						dotted_module_path = ".".join(path_parts)			executed_lines.clear()			executed_lines.union(cov_info.get("executed_lines", set()))						parsed_covdata[dotted_module_path] = executed_lines					return parsed_covdata			def _extract_module_entities(self, dotted_mod_path: str) -> Dict[str, Tuple[int, int]]:		"""			Estrae il range di linee di ogni entità autonoma presente nel modulo			letto il cui source code è stato parsato nel CST `self._module`						Returns			-------				Dict[str, Tuple[int, int]]					Un dizionario di coppie di interi, indicizzato da stringhe, contenente, per ogni					entità autonoma il range di linee		"""		entity_name: str		class_stack: List[str] = list()		inner_node: TreeNode		module_entities: Dict[str, Tuple[int, int]] = dict()				for module_stmt in self._module.named_children:			if module_stmt.type == "class_definition":				self._extract_methods(module_stmt, module_entities, dotted_mod_path, class_stack)			elif module_stmt.type == "decorated_definition":				inner_node = module_stmt.child_by_field_name("definition")				self._extract_methods(inner_node, module_entities, dotted_mod_path, class_stack)			else:				self._extract_ifentity(module_stmt, module_entities)						return module_entities			def _extract_methods(			self,			class_node: TreeNode,			module_entities: Dict[str, Tuple[int, int]],			dotted_mod_path: str,			class_stack: List[str]	):		inner_node: TreeNode		prefix: str				class_stack.append(self._node2text(class_node.child_by_field_name("name")))		for child_node in class_node.children:			if (child_node.type == "class_definition"):				self._extract_methods(child_node, module_entities, dotted_mod_path, class_stack)			elif (child_node.type == "decorated_definition"):				inner_node = child_node.child_by_field_name("definition")				if ((inner_node is not None) and (inner_node.type == "class_definition")):					self._extract_methods(inner_node, module_entities, dotted_mod_path, class_stack)			else:				prefix = f"{dotted_mod_path}.{'$'.join(class_stack)}$"				self._extract_ifentity(child_node, module_entities, prefix=prefix)		class_stack.pop()					def _extract_ifentity(			self,	        module_stmt: TreeNode,			module_entities: Dict[str, Tuple[int, int]],			prefix: str = ""	):		if (module_stmt.type == "decorated_definition"):			inner_node = module_stmt.child_by_field_name("definition")			if (inner_node is not None):				self._add_ifentity_todict(inner_node, module_stmt, module_entities, prefix=prefix)		else:			self._add_ifentity_todict(module_stmt, module_stmt, module_entities, prefix=prefix)							def _add_ifentity_todict(			self,	        name_node: TreeNode,			whole_node: TreeNode,			module_entities: Dict[str, Tuple[int, int]],			prefix: str = ""	):		"""			Aggiunge il range di linee del nodo `whole_node` al dizionario se e solo se			il nodo interno `name_node` corrisponde ad un' entità autonoma.						Il dizionario viene costruito per permettere l' aggregazione dei valori			di statement coverage di ogni modulo		"""		if (name_node.type in self._ENTS_TYPES):			entity_name: str = self._node2text(name_node.child_by_field_name("name"))			entity_name = f"{prefix}{entity_name}"			module_entities[entity_name] = (				whole_node.start_point[0] + 1,				whole_node.end_point[0] + 1			)							def _extract_execlines(self) -> Set[int]:		"""			Estrae i numeri di linea di ogni statement eseguibile presente nel modulo			letto il cui source code è stato parsato nel CST `self._module`						Returns			-------				Set[int]					Un insieme di interi contenente, i numeri di linea che rappresentano					statements eseguibili		"""		executable_lines: Set[int] = set()		self._extract_execlines_rec(self._module, executable_lines)		return executable_lines			def _extract_execlines_rec(self, statement: TreeNode, executable_lines: Set[int]):		if self._is_executable_node(statement):			for lineno in range(				statement.start_point[0]+1,				(statement.end_point[0]+1)+1			):				executable_lines.add(lineno)						for child in statement.children:			self._extract_execlines_rec(child, executable_lines)							def _is_executable_node(self, entity_stmt: TreeNode) -> bool:		"""			Determina se lo statement, di un' entità autonoma, fornito			rappresenta parte del codice eseguibile dell' entità						Parameters			----------				entity_stmt: TreeNode					Un oggetto `tree_sitter.Node` rappresentante lo statement					dell' entità autonoma da verificare								Returns			-------				bool					Un booleano che indica se lo statement fornito rappresenta codice					eseguibile nell' entità autonoma di cui è parte		"""		# Esclusi esplicitamente "pass" statements e "try" statements		if entity_stmt.type in {			"pass_statement",			"try_statement"		}:			return False				entity_stmt_str: str		# Statement di espressione		if entity_stmt.type == "expression_statement":			entity_stmt_str = self._node2text(entity_stmt).strip()			# Statement di espressione senza assegnamento			if (not "=" in entity_stmt_str):				# Definizione di una variabile (senza inizializzazione)				if ":" in entity_stmt_str:					return False				# Possibile espressione costante				elif len(entity_stmt.children) == 1:					if self._is_constant_node(entity_stmt.children[0]):						return False				# Sennò l' expression statement è eseguibile				return True		return True			def _is_constant_node(self, express_stmt: TreeNode) -> bool:		"""			Verifica ricorsivamente se uno statement di un entità autonoma è			un espressione constante						Parameters			----------				express_stmt: TreeNode					Un oggetto `tree_sitter.Node` rappresentante lo statement di espressione,					appartenente ad un' entità autonoma, da verificare								Returns			-------				bool					Un booleano che indica se lo statement di espressione fornito					rappresenta un espressione constante		"""		if express_stmt.type in self._CONSTANT_TYPES:			return True		elif express_stmt.type == "binary_operator":			return all(self._is_constant_node(child) for child in express_stmt.children if child.type != "operator")		else:			return False					def _node2text(self, node: TreeNode) -> str:		return self._module_source[node.start_byte:node.end_byte].decode("utf-8")